836	\section{Algorithm Pseudocode}
837	\label{app:algo}
838	
839	\begin{algorithm}[h]
840	\caption{Binary RL Pipeline (per main-line turn, both tracks)}
841	\label{alg:binary_rl}
842	\begin{algorithmic}[1]
843	\REQUIRE Session/trajectory $\mathcal{T}$, turn $t$, messages $\mathcal{M}_t$
844	\STATE $a_t, \text{logp}_{\text{old}} \leftarrow \text{SGLang}(\mathcal{M}_t)$ \hfill \textit{// serve and collect log-probs}
845	\STATE Buffer $\{\text{prompt\_ids},\, \text{response\_ids},\, \text{logp}_{\text{old}}\}$ for $(\mathcal{T}, t)$
846	\STATE // --- On next turn: extract $s_{t+1}$ and fire PRM ---
847	\STATE $s_{t+1} \leftarrow$ first message of $\mathcal{M}_{t+1}$ \hfill \textit{// user reply or env feedback}
848	\STATE $\{r_i\}_{i=1}^m \leftarrow \text{PRM}(a_t, s_{t+1})$ \hfill \textit{// $m$ parallel votes, async}
849	\STATE $r \leftarrow \text{MajorityVote}(\{r_i\})$
850	\STATE $A_t \leftarrow r$ broadcast
851	\STATE Apply at-least-one guarantee if zero effective samples in $\mathcal{T}$
852	\STATE Submit \texttt{Sample} to trainer queue
853	\end{algorithmic}
854	\end{algorithm}
855	
856	\begin{algorithm}[h]
857	\caption{OPD Pipeline (personal agent track)}
858	\label{alg:opd}
859	\begin{algorithmic}[1]
860	\REQUIRE Turn data $(a_t, \mathcal{M}_t, \text{logp}_{\text{old}})$, next state $s_{t+1}$
861	\STATE $\{(\text{score}_i, \text{hint}_i)\}_{i=1}^m \leftarrow \text{Judge}(a_t, s_{t+1})$
862	\STATE $\text{valid} \leftarrow \{h_i : \text{score}_i = +1 \wedge |h_i| > 10\}$
863	\IF{$\text{valid} = \emptyset$} \STATE \textbf{Drop sample}; \RETURN \ENDIF
864	\STATE $\text{hint} \leftarrow \arg\max_{h \in \text{valid}} |h|$
865	\STATE $s_{\text{enhanced}} \leftarrow \mathcal{M}_t \oplus \texttt{``[user's hint]\textbackslash n\{hint\}''}$
866	\STATE $\log\pi_{\text{teacher}} \leftarrow \text{Teacher}(a_t \mid s_{\text{enhanced}})$
867	\STATE $A_t[k] \leftarrow \log\pi_{\text{teacher}}[k] - \text{logp}_{\text{old}}[k]$
868	\STATE Submit \texttt{Sample}(teacher\_log\_probs=$A_t$) to trainer queue
869	\end{algorithmic}
870	\end{algorithm}
